// === WF-06 [1] Input Validator ===
// Принимаем как Webhook ($json.body), так и Execute Workflow ($json напрямую)
const raw = $input.first().json;
const input = raw.body || raw;

let chatId = input.chatId || input.chat_id || input.chatID;
if (chatId !== undefined && chatId !== null) chatId = String(chatId).trim();

if (!chatId) {
  return [{ json: {
    chatId: '',
    isError: true,
    _route: 1,
    errorText: '\u26A0\uFE0F WF-06: chatId отсутствует в запросе.'
  }}];
}

const type = String(input.type || '').toLowerCase().trim();
const fileId = String(input.file_id || '').trim();
const mime = String(input.mime_type || '').trim();
const fileSize = Number(input.file_size || 0);

// Принимаем только document (PDF/DOCX). photo/voice/text для выписки не подходят.
if (type !== 'document') {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F Для выписки нужен файл PDF или DOCX. Фото и голос не поддерживаются.\n\nОтправьте /vpsk заново и приложите файл выписки.'
  }}];
}

if (!fileId) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F Файл не получен. Попробуйте /vpsk снова.'
  }}];
}

// Лимит Telegram bot — 20 МБ
if (fileSize && fileSize > 20 * 1024 * 1024) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F Файл слишком большой (макс 20 МБ). Telegram Bot API имеет ограничение.'
  }}];
}

return [{ json: {
  chatId,
  type,
  file_id: fileId,
  mime_type: mime,
  file_size: fileSize,
  isError: false,
  _route: 0
}}];

// === WF-06 [2] Fix MIME — выписки (PDF / DOCX / JPEG / PNG) ===
// Telegram присылает .docx / .pdf обычно с правильным mime_type, но иногда
// application/octet-stream — поэтому делаем полную нормализацию (NFR-11).

const item = $input.item;
if (!item.binary || !item.binary.data) {
  throw new Error('WF-06 Fix MIME: no binary data on input item');
}

// 1) Сначала смотрим на mime, который пришёл от Telegram через WF-01
let tgMime = '';
try {
  tgMime = String($('Input Validator').first().json.mime_type || '').toLowerCase();
} catch (e) { tgMime = ''; }

// 2) Расширение файла
const fileName = item.binary.data.fileName || '';
const ext = (fileName.split('.').pop() || '').toLowerCase();
const extMap = {
  'pdf':  'application/pdf',
  'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'jpg':  'image/jpeg',
  'jpeg': 'image/jpeg',
  'png':  'image/png',
  'webp': 'image/webp'
};

let finalMime = (tgMime && tgMime !== 'application/octet-stream') ? tgMime : (extMap[ext] || '');

// 3) Magic bytes — последний рубеж
if (!finalMime || finalMime === 'application/octet-stream') {
  const buf = Buffer.from(item.binary.data.data, 'base64');
  if (buf[0] === 0x25 && buf[1] === 0x50 && buf[2] === 0x44 && buf[3] === 0x46) {
    finalMime = 'application/pdf';                    // %PDF
  } else if (buf[0] === 0x50 && buf[1] === 0x4B && buf[2] === 0x03 && buf[3] === 0x04) {
    finalMime = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
  } else if (buf[0] === 0xFF && buf[1] === 0xD8) {
    finalMime = 'image/jpeg';
  } else if (buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47) {
    finalMime = 'image/png';
  } else {
    throw new Error(`WF-06: cannot determine MIME. File: ${fileName}, bytes: ${buf.slice(0, 8).toString('hex')}`);
  }
}

// 4) Допустимые типы для выписок
const allowed = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'image/jpeg', 'image/png'
];
if (!allowed.includes(finalMime)) {
  throw new Error(`WF-06: unsupported MIME for statement: ${finalMime}. Поддерживается: PDF, DOCX, JPEG, PNG.`);
}

// 5) Перезаписываем
item.binary.data.mimeType = finalMime;
item.binary.data.fileType = finalMime.split('/')[0];

// Прокидываем поля из Input Validator в json
const v = $('Input Validator').first().json;
item.json = {
  ...item.json,
  chatId: v.chatId,
  _detectedMime: finalMime,
  _origFileName: fileName
};

return item;

// ============================================================
// WF-06 [3] Parse Statement — v1.1
// Изменения v1.1: добавлен invoice_number в нормализацию транзакций
// ============================================================

function extractGeminiText(item) {
  if (!item) return '';
  if (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) {
    return item.content.parts[0].text;
  }
  if (typeof item.text === 'string' && item.text.length) return item.text;
  if (typeof item.content === 'string' && item.content.length) return item.content;
  if (Array.isArray(item.content) && item.content[0]) {
    const c0 = item.content[0];
    if (typeof c0 === 'string') return c0;
    if (c0.text) return c0.text;
  }
  if (typeof item.response === 'string') return item.response;
  if (item.message && typeof item.message.content === 'string') return item.message.content;
  if (typeof item.output === 'string') return item.output;
  if (typeof item.generatedText === 'string') return item.generatedText;
  if (item.candidates && item.candidates[0] && item.candidates[0].content) {
    const parts = item.candidates[0].content.parts;
    if (parts && parts[0] && parts[0].text) return parts[0].text;
  }
  return '';
}

function normalizeCountry(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (s.includes('польш') || s.includes('polsk') || s === 'pl') return 'Польша';
  return 'Беларусь';
}

function normalizeBank(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (s.includes('pko')) return 'PKO_BP';
  return 'Priorbank';
}

function normalizeStatus(raw) {
  return String(raw || '').includes('Поступление') ? 'Поступление' : 'Выбытие';
}

function normalizeAmount(raw) {
  if (typeof raw === 'number') return Math.abs(raw);
  const s = String(raw || '').replace(/\s/g, '').replace(',', '.').replace(/[^0-9.\-]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? 0 : Math.abs(n);
}

function normalizeCurrency(raw) {
  const s = String(raw || '').toUpperCase().trim();
  return ['BYN', 'USD', 'EUR', 'PLN'].includes(s) ? s : '';
}

function normalizeDate(raw) {
  const s = String(raw || '').trim();
  if (/^\d{2}\.\d{2}\.\d{4}$/.test(s)) return s;
  const m1 = s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m1) return `${m1[3]}.${m1[2]}.${m1[1]}`;
  const m2 = s.match(/^(\d{4})\/(\d{2})\/(\d{2})$/);
  if (m2) return `${m2[3]}.${m2[2]}.${m2[1]}`;
  return '';
}

function periodFromDate(ddmmyyyy) {
  const m = String(ddmmyyyy || '').match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  return m ? `${m[3]}.${m[2]}` : '';
}

// === v1.1: нормализация номера инвойса ===
function normalizeInvoiceNumber(raw) {
  if (raw === null || raw === undefined) return '';
  const s = String(raw).trim();
  if (!s || s === 'null') return '';
  // Убираем лишние пробелы вокруг разделителей
  return s.replace(/\s*([/\-#])\s*/g, '$1').trim();
}

// === Берём данные ===
const geminiOut = $input.first().json;
const chatId = $('Input Validator').first().json.chatId;
const raw = extractGeminiText(geminiOut);

if (!raw) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F Gemini не вернул ответ. Попробуйте /vpsk снова или используйте файл лучшего качества.'
  }}];
}

// Снимаем markdown-обёртку (NFR-12)
const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

// Сначала проверяем сигнал ошибки от AI (объект, не массив)
if (cleaned.startsWith('{')) {
  try {
    const errObj = JSON.parse(cleaned);
    if (errObj.error === 'NOT_STATEMENT') {
      return [{ json: {
        chatId, isError: true, _route: 1,
        errorText: '\u274C Файл не похож на банковскую выписку.\n\nОжидается: Приорбанк (.docx) или PKO Bank Polski (.pdf).\n\nОтправьте /vpsk заново и приложите выписку.'
      }}];
    }
    if (errObj.error === 'НЕЧИТАЕМ') {
      return [{ json: {
        chatId, isError: true, _route: 1,
        errorText: '\u274C Выписка нечитаема. Отправьте файл лучшего качества или другой формат.'
      }}];
    }
  } catch (e) { /* падаем дальше — попробуем как массив */ }
}

// Извлекаем массив
let parsed;
try {
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (!m) throw new Error('No JSON array found');
  parsed = JSON.parse(m[0]);
  if (!Array.isArray(parsed)) throw new Error('Parsed value is not an array');
} catch (e) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u274C Не удалось распарсить ответ Gemini как JSON-массив.',
    _parseError: e.message,
    _rawSample: cleaned.slice(0, 200)
  }}];
}

if (parsed.length === 0) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F В выписке не найдено ни одной транзакции. Проверьте, что файл — действительно выписка с операциями.'
  }}];
}

// === Нормализация каждой транзакции (v1.1 — добавлен invoice_number) ===
const normalized = parsed.map(tx => {
  const dateDoc  = normalizeDate(tx.date_doc);
  const datePaid = normalizeDate(tx.date_paid) || dateDoc;
  return {
    bank:           normalizeBank(tx.bank),
    country:        normalizeCountry(tx.country),
    period:         String(tx.period || '').trim() || periodFromDate(dateDoc),
    status:         normalizeStatus(tx.status),
    date_doc:       dateDoc,
    date_paid:      datePaid,
    counterparty:   (tx.counterparty === null || tx.counterparty === undefined) ? '' : String(tx.counterparty).trim(),
    amount:         normalizeAmount(tx.amount),
    currency:       normalizeCurrency(tx.currency),
    invoice_number: normalizeInvoiceNumber(tx.invoice_number),  // ← v1.1
    description:    String(tx.description || '').trim()
  };
}).filter(tx => tx.amount > 0 && tx.currency && tx.date_doc && tx.period);

if (normalized.length === 0) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: '\u26A0\uFE0F После нормализации не осталось валидных транзакций (нет суммы / валюты / даты). Проверьте качество файла.'
  }}];
}

// === Консенсус по банку / стране / периоду ===
function mode(arr) {
  const cnt = {};
  arr.forEach(v => { if (v) cnt[v] = (cnt[v] || 0) + 1; });
  let best = '', bestN = 0;
  for (const k in cnt) if (cnt[k] > bestN) { best = k; bestN = cnt[k]; }
  return best;
}

const bank    = mode(normalized.map(t => t.bank))    || normalized[0].bank;
const country = mode(normalized.map(t => t.country)) || normalized[0].country;
const period  = mode(normalized.map(t => t.period))  || normalized[0].period;

const expectedCountry = bank === 'PKO_BP' ? 'Польша' : 'Беларусь';
if (country !== expectedCountry) {
  return [{ json: {
    chatId, isError: true, _route: 1,
    errorText: `\u26A0\uFE0F Несогласованные данные: банк ${bank}, страна ${country}. Проверьте файл.`
  }}];
}

// === Сводка для подтверждения ===
let countIn = 0, countOut = 0, sumIn = 0, sumOut = 0;
const dates = [];
for (const t of normalized) {
  if (t.status === 'Поступление') { countIn++; sumIn += t.amount; }
  else                            { countOut++; sumOut += t.amount; }
  if (t.date_doc) dates.push(t.date_doc);
}

function toIso(ddmmyyyy) {
  const m = ddmmyyyy.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : '';
}
const isoDates = dates.map(toIso).filter(Boolean).sort();
const periodFrom = isoDates[0]                 ? isoDates[0].split('-').reverse().join('.')                 : '';
const periodTo   = isoDates[isoDates.length-1] ? isoDates[isoDates.length-1].split('-').reverse().join('.') : '';

const currencies = Array.from(new Set(normalized.map(t => t.currency).filter(Boolean)));
const mainCurrency = currencies.length === 1 ? currencies[0] : '';

return [{ json: {
  chatId,
  isError: false,
  _route: 0,
  bank,
  country,
  period,
  countIn,
  countOut,
  sumIn,
  sumOut,
  mainCurrency,
  currencies,
  periodFrom,
  periodTo,
  total: normalized.length,
  transactions: normalized
}}];

// ============================================================
// WF-06 [4] Build Dataset — v1.1
// Изменения v1.1: добавлен 'Номер инвойса (банк)' в объект newRows
// ============================================================

const meta = $('Parse Statement').first().json;
const { bank, country, period, transactions } = meta;

const existing = $input.all().map(i => i.json).filter(r => {
  return r && r['bank_id'];
});

// 1) Старые строки этого триплета — исключаем (перезагрузка выписки, NFR-17)
const keptRows = existing.filter(r => !(
  String(r['Страна']) === country &&
  String(r['Период']) === period &&
  String(r['Банк'])   === bank
));

// 2) Максимальный seq в (Country, Period) среди kept
const countryCode = country === 'Польша' ? 'PL' : 'BY';
const yearMonth = period.replace('.', '');
const seqPrefix = `${countryCode}_${yearMonth}_`;

let maxSeq = 0;
for (const r of keptRows) {
  const id = String(r['bank_id'] || '');
  if (id.startsWith(seqPrefix)) {
    const n = parseInt(id.slice(seqPrefix.length), 10);
    if (!isNaN(n) && n > maxSeq) maxSeq = n;
  }
}

// 3) Назначаем bank_id новым строкам (v1.1 — добавлен 'Номер инвойса (банк)')
const newRows = transactions.map((tx, idx) => {
  const seq = maxSeq + idx + 1;
  const bankId = `${seqPrefix}${String(seq).padStart(4, '0')}`;
  return {
    'bank_id':                bankId,
    'Банк':                   tx.bank,
    'Период':                 tx.period,
    'Страна':                 tx.country,
    'Статус':                 tx.status,
    'Дата документа':         tx.date_doc,
    'Контрагент':             tx.counterparty || '',
    'Дата оплаты':            tx.date_paid,
    'Сумма':                  tx.amount,
    'Валюта':                 tx.currency,
    'Описание':               tx.description,
    'Номер инвойса (банк)':   tx.invoice_number || '',   // ← v1.1
    'Статус сверки':          'PENDING',
    'UUID реестра':           ''
  };
});

// 4) Финальный сет: kept + new
return [{
  json: {
    chatId:          meta.chatId,
    bank,
    country,
    period,
    countIn:         meta.countIn,
    countOut:        meta.countOut,
    sumIn:           meta.sumIn,
    sumOut:          meta.sumOut,
    mainCurrency:    meta.mainCurrency,
    currencies:      meta.currencies,
    periodFrom:      meta.periodFrom,
    periodTo:        meta.periodTo,
    total:           meta.total,
    transactions:    meta.transactions,
    droppedOldCount: existing.length - keptRows.length,
    finalRowset:     keptRows.concat(newRows),
    keptCount:       keptRows.length,
    newCount:        newRows.length
  }
}];

// === WF-06 [5a] Explode rows — превращаем массив finalRowset в N items ===

const meta = $('Build Dataset').first().json;
const rowset = meta.finalRowset || [];

if (rowset.length === 0) {
  return [{ json: {
    _empty: true,
    chatId: meta.chatId,
    _meta: meta
  }}];
}

return rowset.map(row => ({
  json: {
    ...row,
    chatId: meta.chatId,
    _empty: false
  }
}));

// ============================================================
// WF-06 [6] Build Confirmation — v1.1
// Изменения v1.1: добавлена строка 🧾 с количеством транзакций с инвойсами
// ============================================================

const d = $('Build Dataset').first().json;

const flag = d.country === 'Польша'
  ? '\uD83C\uDDF5\uD83C\uDDF1'  // 🇵🇱
  : '\uD83C\uDDE7\uD83C\uDDFE'; // 🇧🇾

const bankLabel = d.bank === 'PKO_BP' ? 'PKO Bank Polski' : 'Priorbank';

function fmt(n) {
  const v = Number(n) || 0;
  return Number.isInteger(v) ? String(v) : v.toFixed(2);
}

const inLine  = `   Поступлений: ${d.countIn} (+${fmt(d.sumIn)} ${d.mainCurrency || ''})`;
const outLine = `   Выбытий: ${d.countOut} (-${fmt(d.sumOut)} ${d.mainCurrency || ''})`;

const currencyNote = (!d.mainCurrency && d.currencies && d.currencies.length > 1)
  ? `\n   \u26A0\uFE0F В выписке несколько валют: ${d.currencies.join(', ')}`
  : '';

const replaceNote = d.droppedOldCount > 0
  ? `\n\u267B\uFE0F Заменено ${d.droppedOldCount} строк предыдущей загрузки за этот период.`
  : '';

// === v1.1: счётчик транзакций с номером инвойса ===
const withInvoice = (d.transactions || []).filter(t => t.invoice_number && t.invoice_number !== '').length;
const invoiceLine = `\n\uD83E\uDDFE С номером инвойса: ${withInvoice} из ${d.total}`;

const confirmationText =
`\u2705 Выписка загружена

${flag} ${d.country} | ${bankLabel}
\uD83D\uDCC5 Период: ${d.periodFrom || '\u2014'} \u2014 ${d.periodTo || '\u2014'}
\uD83D\uDCCA Транзакций: ${d.total}
${inLine}
${outLine}${currencyNote}${invoiceLine}${replaceNote}

Запустите /reconcile для сверки с реестром.`;

return [{ json: {
  chatId: d.chatId,
  confirmationText,
  isError: false,
  bank: d.bank,
  country: d.country,
  period: d.period,
  total: d.total
}}];

// === WF-06 [E] Build Error — единая точка для путей ошибок ===
const d = $input.first().json;
return [{ json: {
  chatId: d.chatId || '',
  confirmationText: d.errorText || '\u274C Произошла неизвестная ошибка при обработке выписки.',
  isError: true
}}];
